                ["shifter"] = ("Taste Shifter", "🌊", "Your preferences are actively evolving."),
                ["omnivore"] = ("Movie Omnivore", "🍿", "You enjoy everything equally — a true cinephile."),
                ["newcomer"] = ("Fresh Eyes", "👀", "Just getting started — your taste is forming.")
            };

