                    GenreName = genre.ToString(),
                    EarlyWeight = Math.Round(earlyAvg * 100, 1),
                    RecentWeight = Math.Round(recentAvg * 100, 1),
                    Delta = Math.Round(delta * 100, 1),
                    Direction = direction,
                    Emoji = emoji
                });
            }

            return drifts.OrderByDescending(d => Math.Abs(d.Delta)).ToList();
